import React, { useState } from 'react';
import './credenciales.css';
import { Link } from 'react-router-dom';

function CredencialesUsuario() {
  const [nombre, setNombre] = useState("");
  const [grado, setGrado] = useState("");

  // Validación: nombre no vacío y grado seleccionado
  const puedeComenzar = nombre.trim() !== "" && grado !== "";

  return (
    <div className="contenedor-credenciales_usuario">
      <h2 className="titulo-de-bloque-1">REGISTRO</h2>
      
      <div className="espacios_de_credenciales">
        <label className="label_credenciales">Nombre:</label>
        <input 
          type="text" 
          placeholder="Nombre" 
          className="estilo_de_input_1"
          onChange={(e) => setNombre(e.target.value)}
        />
      </div>

      <div className="espacios_de_credenciales">
        <label className="label_credenciales">Grado:</label>
        <select 
          className="estilo_de_input_2"
          onChange={(e) => setGrado(e.target.value)}
          defaultValue=""
        >
          <option value="" disabled>Selecciona Grado</option>
          <option value="4/5">4/5</option>
          <option value="6/7">6/7</option>
          <option value="8/9">8/9</option>
          <option value="10/11">10/11</option>
        </select>
      </div>

      <div className="opciones-de-sesion">
        <button className="btn_Comenzar">Administrador</button>
        
        {/* El Link solo funciona si 'puedeComenzar' es true */}
        <Link 
          to={puedeComenzar ? "/prueba" : "#"} 
          style={{ pointerEvents: puedeComenzar ? 'auto' : 'none', textDecoration: 'none' }}
        >
          <button 
            className="btn_Comenzar" 
            disabled={!puedeComenzar}
            style={{ opacity: puedeComenzar ? 1 : 0.5 }}
          >
            Comenzar
          </button>
        </Link>
      </div>
    </div>
  );
}

export default CredencialesUsuario;
